+func TestFormatCycle(t *testing.T) {
+	if got := formatCycle(nil); got != "(empty)" {
+		t.Fatalf("expected (empty), got %q", got)
+	}
+	c := []string{"X", "Y", "Z"}
+	want := "X → Y → Z → X"
+	if got := formatCycle(c); got != want {
+		t.Fatalf("formatCycle mismatch: got %q want %q", got, want)
+	}
+}
